from collections import deque
n,k=map(int,input().split())
p=list(map(int,input().split()))
ch=[[] for _ in range(n)]
root=0
for i,par in enumerate(p):
    if par==-1:root=i
    else:ch[par].append(i)
q=deque([(root,0)])
cnt=0
while q:
    u,d=q.popleft()
    if d==k:cnt+=1
    elif d<k:
        for c in ch[u]:q.append((c,d+1))
print(cnt)

